    "cards": [
      {
        "front": "What is a context manager?",
        "back": "A context manager is a Python construct that allows you to allocate and release resources precisely when you want to.",
        "icon": "🔍"
      },
      {
        "front": "How do you create a context manager?",
        "back": "You can create a context manager using the 'with' statement or by defining a class with '__enter__' and '__exit__' methods.",
        "icon": "🛠️"
      },
      {
        "front": "What is the purpose of the 'with' statement?",
        "back": "The 'with' statement simplifies exception handling by encapsulating common preparation and cleanup tasks.",
        "icon": "✅"
      },
      {
        "front": "Can you use context managers with files?",
        "back": "Yes, context managers are commonly used for file operations to ensure files are properly closed after their suite finishes.",
        "icon": "📄"
      }
    ]
  }
}
